import React from "react";

export default function MonitorCard({
  mode,
  username,
  password,
  setUsername,
  setPassword,
  setMode,
  handleSubmit,
  message
}) {
  return (
    <div className="monitor-wrapper">
      <div className="monitor-frame">
        <div className="monitor-screen">
          <div className="left-panel">
            <h1 className="brand-title">Cake Talk</h1>

            <div className="cake-illustration">
              <div className="cake-top"></div>
              <div className="cake-bottom"></div>
              <div className="flower flower-top"></div>
              <div className="flower flower-bottom"></div>
            </div>
          </div>

          <div className="right-panel">
            <h2 className="form-title">
              {mode === "login" ? "User Login" : "Sign Up"}
            </h2>

            <form onSubmit={handleSubmit} className="auth-form">
              <label>username / e-mail</label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Enter username or email"
              />

              <label>password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter password"
              />

              <button type="submit" className="confirm-btn">
                {mode === "login" ? "CONFIRM" : "CREATE ACCOUNT"}
              </button>
            </form>

            <div className="switch-row">
              {mode === "login" ? (
                <>
                  <span>Need an account?</span>
                  <button
                    type="button"
                    className="link-btn"
                    onClick={() => {
                      setMode("signup");
                    }}
                  >
                    Sign up
                  </button>
                </>
              ) : (
                <>
                  <span>Already have an account?</span>
                  <button
                    type="button"
                    className="link-btn"
                    onClick={() => {
                      setMode("login");
                    }}
                  >
                    Log in
                  </button>
                </>
              )}
            </div>

            {mode === "login" && (
              <div className="forgot-text">forgot username | password</div>
            )}

            {message && <p className="message-text">{message}</p>}
          </div>
        </div>
      </div>

      <div className="monitor-stand"></div>
      <div className="monitor-base"></div>
    </div>
  );
}
